import express from "express";
import Product from "../models/Product.js";
import upload from "../middlewares/multer.js";
import {
  uploadToCloudinary,
  deleteFromCloudinary,
} from "../utils/cloudinary.js";

const router = express.Router();

/**
 * ➡️ Create a new product
 */
router.post("/", upload.single("image"), async (req, res) => {
  try {
    console.log("Create request body:", req.body);
    console.log("Create request file:", req.file ? "File received" : "No file");

    const { name, description, price, isAvailable, onOffer } = req.body;

    // Normalize values
    const parsedPrice =
      price !== undefined && !isNaN(parseFloat(price))
        ? parseFloat(price)
        : 0;

    const isAvailableValue =
      isAvailable === "true" || isAvailable === true ? true : false;

    const onOfferValue =
      onOffer === "true" || onOffer === true ? true : false;

    // Upload image if provided
    let imageUrl = null;
    let cloudinaryPublicId = null;
    if (req.file) {
      const result = await uploadToCloudinary(
        req.file.buffer,
        "nadir-brothers/products"
      );
      imageUrl = result.secure_url;
      cloudinaryPublicId = result.public_id;
    }

    const newProduct = new Product({
      name: name?.trim(),
      description: description?.trim(),
      price: parsedPrice,
      isAvailable: isAvailableValue,
      onOffer: onOfferValue,
      image: imageUrl,
      cloudinaryPublicId,
    });

    const saved = await newProduct.save();
    res.status(201).json(saved);
  } catch (err) {
    console.error("❌ Error creating product:", err);
    res.status(500).json({ error: "Failed to create product" });
  }
});

/**
 * ➡️ Get all products
 */
router.get("/", async (req, res) => {
  try {
    const products = await Product.find().sort({ createdAt: -1 });
    res.json(products);
  } catch (err) {
    res.status(500).json({ error: "Failed to fetch products" });
  }
});

/**
 * ➡️ Get single product
 */
router.get("/:id", async (req, res) => {
  try {
    const product = await Product.findById(req.params.id);
    if (!product)
      return res.status(404).json({ message: "Product not found" });
    res.json(product);
  } catch (err) {
    res.status(500).json({ error: "Failed to fetch product" });
  }
});

/**
 * ➡️ Update product
 */
router.put("/:id", upload.single("image"), async (req, res) => {
  try {
    console.log("Update request body:", req.body);
    console.log("Update request file:", req.file ? "File received" : "No file");

    const { name, description, price, isAvailable, onOffer } = req.body;
    const product = await Product.findById(req.params.id);

    if (!product) {
      return res.status(404).json({ message: "Product not found" });
    }

    // Normalize values
    const parsedPrice =
      price !== undefined && !isNaN(parseFloat(price))
        ? parseFloat(price)
        : product.price;

    const isAvailableValue =
      isAvailable !== undefined
        ? isAvailable === "true" || isAvailable === true
        : product.isAvailable;

    const onOfferValue =
      onOffer !== undefined
        ? onOffer === "true" || onOffer === true
        : product.onOffer;

    // Update fields
    product.name = name?.trim() || product.name;
    product.description = description?.trim() || product.description;
    product.price = parsedPrice;
    product.isAvailable = isAvailableValue;
    product.onOffer = onOfferValue;

    // Handle image update
    if (req.file) {
      if (product.cloudinaryPublicId) {
        await deleteFromCloudinary(product.cloudinaryPublicId);
        console.log("✅ Old image deleted from Cloudinary");
      }
      const result = await uploadToCloudinary(
        req.file.buffer,
        "nadir-brothers/products"
      );
      product.image = result.secure_url;
      product.cloudinaryPublicId = result.public_id;
      console.log("✅ New image uploaded:", result.secure_url);
    }

    const updated = await product.save();
    res.json(updated);
  } catch (err) {
    console.error("❌ Error updating product:", err);
    res.status(500).json({ error: "Failed to update product" });
  }
});

/**
 * ➡️ Delete product
 */
router.delete("/:id", async (req, res) => {
  try {
    const product = await Product.findById(req.params.id);
    if (!product)
      return res.status(404).json({ message: "Product not found" });

    if (product.cloudinaryPublicId) {
      await deleteFromCloudinary(product.cloudinaryPublicId);
      console.log("✅ Image deleted from Cloudinary");
    }

    await Product.findByIdAndDelete(req.params.id);
    res.json({ message: "Product deleted successfully" });
  } catch (err) {
    console.error("❌ Error deleting product:", err);
    res.status(500).json({ error: "Failed to delete product" });
  }
});

export default router;
